import{_ as n,c as r,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Datenschutzrichtlinie: Datenschutz verstehen | OpenCodeDocs","description":"Erfahren Sie mehr über die Datenschutzrichtlinie und Datenschutzmaßnahmen von OpenCodeDocs. Wie wir personenbezogene Daten sammeln, verwenden, speichern und welche Rechte Sie an Ihren Daten haben.","frontmatter":{"title":"Datenschutzrichtlinie: Datenschutz verstehen | OpenCodeDocs","sidebarTitle":"Wohin gehen Ihre Daten?","subtitle":"Datenschutzrichtlinie: Datenschutz verstehen","description":"Erfahren Sie mehr über die Datenschutzrichtlinie und Datenschutzmaßnahmen von OpenCodeDocs. Wie wir personenbezogene Daten sammeln, verwenden, speichern und welche Rechte Sie an Ihren Daten haben."},"headers":[],"relativePath":"de/privacy.md","filePath":"de/privacy.md"}'),a={name:"de/privacy.md"};function o(s,e,l,h,u,d){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="datenschutzrichtlinie" tabindex="-1">Datenschutzrichtlinie <a class="header-anchor" href="#datenschutzrichtlinie" aria-label="Permalink to &quot;Datenschutzrichtlinie&quot;">​</a></h1><p>Zuletzt aktualisiert: 2026-01-01</p><p>Vielen Dank, dass Sie OpenCodeDocs verwenden. Wir nehmen Ihren Datenschutz und den Schutz Ihrer personenbezogenen Daten sehr ernst. Diese Datenschutzrichtlinie hilft Ihnen zu verstehen, wie wir Ihre personenbezogenen Daten sammeln, verwenden, speichern und schützen.</p><h2 id="_1-informationen-die-wir-sammeln" tabindex="-1">1. Informationen, die wir sammeln <a class="header-anchor" href="#_1-informationen-die-wir-sammeln" aria-label="Permalink to &quot;1. Informationen, die wir sammeln&quot;">​</a></h2><p>Bei der Nutzung der OpenCodeDocs-Dienste können wir folgende Arten von Informationen sammeln:</p><h3 id="kontoinformationen" tabindex="-1">Kontoinformationen <a class="header-anchor" href="#kontoinformationen" aria-label="Permalink to &quot;Kontoinformationen&quot;">​</a></h3><ul><li><strong>E-Mail-Adresse</strong>: Für die Kontoregistrierung, Anmeldeüberprüfung und wichtige Benachrichtigungen</li><li><strong>Benutzername</strong>: Der von Ihnen gewählte Anzeigename</li><li><strong>GitHub-Kontoinformationen</strong>: Wenn Sie sich mit GitHub anmelden, erhalten wir Ihre öffentlichen Informationen</li></ul><h3 id="nutzungsdaten" tabindex="-1">Nutzungsdaten <a class="header-anchor" href="#nutzungsdaten" aria-label="Permalink to &quot;Nutzungsdaten&quot;">​</a></h3><ul><li><strong>Browserverlauf</strong>: Die von Ihnen besuchten Tutorial-Seiten und der Zeitpunkt des Besuchs</li><li><strong>Interaktionsverhalten</strong>: Operationen wie Code-Kopieren und Kapitelwechsel</li><li><strong>Suchverlauf</strong>: Ihre Suchbegriffe auf der Website</li></ul><h3 id="gerateinformationen" tabindex="-1">Geräteinformationen <a class="header-anchor" href="#gerateinformationen" aria-label="Permalink to &quot;Geräteinformationen&quot;">​</a></h3><ul><li><strong>Browser-Typ</strong>: Chrome, Firefox, Safari usw.</li><li><strong>Betriebssystem</strong>: Windows, macOS, Linux usw.</li><li><strong>IP-Adresse</strong>: Für Sicherheitsmaßnahmen und regionale Optimierung</li></ul><h2 id="_2-verwendung-von-informationen" tabindex="-1">2. Verwendung von Informationen <a class="header-anchor" href="#_2-verwendung-von-informationen" aria-label="Permalink to &quot;2. Verwendung von Informationen&quot;">​</a></h2><p>Die gesammelten Informationen werden für folgende Zwecke verwendet:</p><ul><li><strong>Dienste bereitstellen</strong>: Sicherstellen, dass Sie Tutorial-Inhalte normal aufrufen und nutzen können</li><li><strong>Personalisierte Erfahrung</strong>: Ihren Lesefortschritt und Ihre bevorzugten Einstellungen speichern</li><li><strong>Produktverbesserung</strong>: Nutzungsmuster analysieren, Inhalte und Funktionen optimieren</li><li><strong>Sicherheitsmaßnahmen</strong>: Anormales Verhalten erkennen, Missbrauch verhindern</li><li><strong>Benachrichtigungen senden</strong>: Aktualisierungen von Tutorials und wichtige Ankündigungen senden (kann abbestellt werden)</li></ul><h2 id="_3-informationsfreigabe-und-offenlegung" tabindex="-1">3. Informationsfreigabe und Offenlegung <a class="header-anchor" href="#_3-informationsfreigabe-und-offenlegung" aria-label="Permalink to &quot;3. Informationsfreigabe und Offenlegung&quot;">​</a></h2><p>Wir verkaufen Ihre personenbezogenen Daten nicht. Eine Freigabe ist nur in folgenden Fällen möglich:</p><ul><li><strong>Drittanbieter-Dienstleister</strong>: Wie Vercel (Hosting), Plausible (Analytics), sie haben nur Zugriff auf die Informationen, die zur Erfüllung ihrer Aufgaben erforderlich sind</li><li><strong>Gesetzliche Anforderungen</strong>: Offenlegung gemäß Gesetzen und Vorschriften oder behördlichen Anforderungen</li><li><strong>Rechtsschutz</strong>: Zum Schutz von OpenCodeDocs und der Rechte der Benutzer in notwendigen Situationen</li></ul><h2 id="_4-datenspeicherung-und-sicherheit" tabindex="-1">4. Datenspeicherung und -sicherheit <a class="header-anchor" href="#_4-datenspeicherung-und-sicherheit" aria-label="Permalink to &quot;4. Datenspeicherung und -sicherheit&quot;">​</a></h2><ul><li><strong>Speicherort</strong>: Daten werden auf sicheren Servern in den USA und im asiatisch-pazifischen Raum gespeichert</li><li><strong>Verschlüsselungsmaßnahmen</strong>: Übertragungsdaten werden mit TLS/SSL verschlüsselt, sensible Daten werden mit AES-256 verschlüsselt gespeichert</li><li><strong>Zugriffskontrolle</strong>: Streng beschränkter Zugriff von internen Mitarbeitern auf Daten</li><li><strong>Aufbewahrungsfrist</strong>: Nach der Kündigung des Kontos werden personenbezogene Daten innerhalb von 30 Tagen gelöscht</li></ul><h2 id="_5-ihre-rechte" tabindex="-1">5. Ihre Rechte <a class="header-anchor" href="#_5-ihre-rechte" aria-label="Permalink to &quot;5. Ihre Rechte&quot;">​</a></h2><p>Gemäß dem Gesetz über den Schutz personenbezogener Informationen und der GDPR haben Sie folgende Rechte:</p><ul><li><strong>Zugriffsrecht</strong>: Sie haben das Recht, die über Sie gespeicherten personenbezogenen Informationen einzusehen</li><li><strong>Korrekturrecht</strong>: Sie haben das Recht, die Korrektur ungenauer personenbezogener Informationen zu fordern</li><li><strong>Löschrecht</strong>: Sie haben das Recht, die Löschung Ihrer personenbezogenen Informationen zu fordern</li><li><strong>Exportrecht</strong>: Sie haben das Recht, Ihre Daten in einem gängigen Format zu exportieren</li><li><strong>Widerruf der Einwilligung</strong>: Sie haben das Recht, Ihre zuvor erteilte Einwilligung jederzeit zu widerrufen</li></ul><p>Wenn Sie diese Rechte ausüben möchten, kontaktieren Sie uns bitte über die untenstehenden Kontaktinformationen.</p><h2 id="_6-cookie-richtlinie" tabindex="-1">6. Cookie-Richtlinie <a class="header-anchor" href="#_6-cookie-richtlinie" aria-label="Permalink to &quot;6. Cookie-Richtlinie&quot;">​</a></h2><p>Wir verwenden folgende Arten von Cookies:</p><ul><li><strong>Notwendige Cookies</strong>: Beibehaltung des Anmeldestatus, Speicherung von Spracheinstellungen</li><li><strong>Analytics-Cookies</strong>: Statistiken über Zugriffe und Nutzungsmuster (unter Verwendung der datenschutzfreundlichen Lösung Plausible)</li><li><strong>Werbungs-Cookies</strong>: <ul><li>Drittanbieter (einschließlich Google) verwenden Cookies, um Werbung basierend auf den früheren Besuchen eines Nutzers auf Ihrer Website oder anderen Websites zu schalten.</li><li>Google verwendet Werbe-Cookies, um Google und seinen Partnern das Schalten von Werbung basierend auf den Besuchen eines Nutzers auf Ihrer Website und/oder anderen Websites im Internet zu ermöglichen.</li><li>Nutzer können die <a href="https://www.google.com/settings/ads" target="_blank" rel="noreferrer">Google-Anzeigeneinstellungen</a> besuchen, um personalisierte Werbung zu deaktivieren. Alternativ können Sie Nutzer auf <a href="http://www.aboutads.info/choices/" target="_blank" rel="noreferrer">www.aboutads.info</a> verweisen, um Cookies von Drittanbietern für personalisierte Werbung zu deaktivieren.</li></ul></li></ul><p>Sie können Cookies über die Browsereinstellungen verwalten. Das Deaktivieren notwendiger Cookies kann die ordnungsgemäße Nutzung einiger Funktionen beeinträchtigen.</p><h2 id="_7-kontaktieren-sie-uns" tabindex="-1">7. Kontaktieren Sie uns <a class="header-anchor" href="#_7-kontaktieren-sie-uns" aria-label="Permalink to &quot;7. Kontaktieren Sie uns&quot;">​</a></h2><p>Wenn Sie Fragen zu dieser Datenschutzrichtlinie haben oder Ihre Datenrechte ausüben möchten, kontaktieren Sie uns bitte unter:</p><ul><li><strong>E-Mail</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Antwortzeit</strong>: Wir werden Ihre Anfrage innerhalb von 15 Arbeitstagen beantworten</li></ul>',30)])])}const f=n(a,[["render",o]]);export{c as __pageData,f as default};
